import React from "react";
import SVGChevron from "../SVGChevron";

export default (props) => (
  <button
    onClick={ () => props.onClick() }
    css={{
      position: "fixed",
      bottom: 0,
      right: 55,
      background: props.theme === "light"
        ? "linear-gradient(45deg, white, #F5F5F5)"
        : "linear-gradient(45deg, black, #050505)",
      zIndex: 20,
    }}
  >
    <div css={{
      height: 19.85,
      display: "flex",
      flexDirection: "column",
      color: props.theme === "light" ? "black" : "white",
    }}>
      <SVGChevron
        size={ 15 }
        cssProps={{
          transform: `translate(${props.open ? 5 : -5}px, 5px) rotate(90deg)`,
          transition: "transform 0.2s ease",
        }}
      />
      <SVGChevron
        size={ 15 }
        cssProps={{
          transform: `translate(${5 - (props.open ? 5 : -5)}px, -5px) rotate(270deg)`,
          transition: "transform 0.2s ease",
        }}
      />
    </div>
  </button>
);
