import React from "react";
import { css } from "glamor";
import Link from "../Link";
import navigation from "../../assets/navigation.yaml";
import arrows from "../../assets/base64/arrows.yaml";

const opened = css({
  opacity: 1,
  transform: "scale(1) translateY(0) !important",
});
const closed = css({
  opacity: 0,
  transform: "scale(.9) translateY(-10px)",
  pointerEvents: "none",
});

function openNav(i) {
  if (document) {
    let element = document.querySelector(`.MoreLinks-${i} ul`);
    element.classList.remove(`${closed}`);
    element.classList.add(`${opened}`);
  }
}
function closeNav(i) {
  if (document) {
    let element = document.querySelector(`.MoreLinks-${i} ul`);
    element.classList.add(`${closed}`);
    element.classList.remove(`${opened}`);
  }
}

export default (props) => (
  <div css={{
    display: "flex",
    alignItems: "center",
    marginRight: "15px",
    zIndex: 10,
  }}>
    <ul css={{
      listStyle: "none",
      margin: 0,
      padding: 0,
    }}>
      {
        navigation.header.left.map((item, i) => {
          if (item.more) {
            return (
              <li
                key={i}
                className={ `MoreLinks-${i}` }
                css={{
                  padding: "10px 15px",
                  display: "inline-block",
                  color: "#ddd",
                  transform: "translateZ(0px)",
                  transition: "color .3s ease",
                  ":hover": {
                    color: "#fff",
                    filter: "brightness(105%)",
                  },
                }}
                onMouseEnter={ (event) => openNav(i) }
                onMouseLeave={ (event) => closeNav(i) }
              >
                <span css={{
                  display: "flex",
                  ":after": {
                    content: "﻿",
                    backgroundImage: `url(${arrows.dropdown.light})`,
                    backgroundRepeat: "no-repeat",
                    backgroundPosition: "50% 50%",
                    backgroundSize: "cover",
                    width: 16,
                    height: "100%",
                    alignSelf: "center",
                    marginLeft: 5,
                  },
                }}>
                  { item.name }
                </span>
                <ul
                  className={ `${closed}` }
                  css={{
                    position: "absolute",
                    minWidth: 122,
                    listStyle: "none",
                    marginTop: "10px",
                    padding: "3px",
                    backgroundColor: "#f5f5f5",
                    borderRadius: "3px",
                    boxShadow: "0 15px 25px -8px rgba(0, 0, 0, .1)",
                    transition: "opacity .125s ease, transform .125s ease",
                  }}
                >
                  {
                    item.more.map((subItem, i) => (
                      <Link to={ subItem.link } key={ i }>
                        <li css={{
                          padding: "5px 10px",
                          color: "#777",
                          fontSize: ".9em",
                          borderRadius: "3px",
                          ":hover": {
                            color: "#555",
                            backgroundColor: "#eee"
                          }
                        }}>{ subItem.name }</li>
                      </Link>
                    ))
                  }
                </ul>
              </li>
            );
          }
          else {
            return (
              <Link to={ item.link } key={ i }>
                <li css={{
                  padding: "10px 15px",
                  display: "inline-block",
                  color: item.button ? "#070A0C" : "#ddd",
                  borderRadius: "3px",
                  background: item.button ? "linear-gradient(45deg, #40C4FB 50%, #62D9FB)" : "none",
                  transition: "filter .3s ease",
                  transform: "translateZ(0px)",
                  ":hover": {
                    color: item.button ? "#070A0C" : "#fff",
                    filter: "brightness(105%)",
                  },
                }}>{ item.name }</li>
              </Link>
            );
          }
        })
      }
    </ul>
  </div>
);
