import React from "react";
import Particles from "react-particles-js";

import halloweenbg from "../../assets/halloween_bg.jpg";
import pridebg from "../../assets/pride_bg.png";

export default () => {
  let today = new Date();

  if (today.getMonth() === 5) {
    return (
      <div css={{
        background: "url(" + pridebg + ")",
        backgroundRepeat: "no-repeat",
        position: "absolute",
        "@media (min-width: 1920px)": {
          backgroundSize: "100% 100%",
        },
        height: 500,
        bottom: "-10vh",
        left: 0,
        width: "100%",
        pointerEvents: "none",
        zIndex: -10,
      }}>
      </div>
    );
  }
  else if (today.getMonth() === 9) {
    return (
      <div css={{
        background: "url(" + halloweenbg + ")",
        position: "fixed",
        backgroundSize: "40%",
        height: "100vh",
        left: 0,
        width: "100vw",
        pointerEvents: "none",
        filter: "brightness(10%) hue-rotate(150deg)",
        zIndex: -10,
      }}>
      </div>
    );
  }
  else if (today.getMonth() === 11) {
    return (
      <Particles
        params={{
          particles: {
            number: {
              value: 100,
              density: {
                enable: false,
              },
            },
            size: {
              value: 5,
              random: true,
            },
            move: {
              random: true,
              direction: "bottom",
              out_mode: "out",
            },
            line_linked: {
              enable: false,
            },
          },
          interactivity: {
            events: {
              onclick: {
                enable: true,
                mode: "remove",
              },
            },
            modes: {
              remove: {
                particles_nb: 10,
              },
            },
          },
        }}
        css={{
          background: "transparent",
          position: "fixed",
          top: 0,
          bottom: 0,
          left: 0,
          right: 0,
          pointerEvents: "none",
        }}
      />
    );
  }
  else {
    return <></>;
  }
};
